 1	import React, { FC, memo, ReactNode, useRef, useState } from 'react';
 2	
 3	import DropdownToggle from '@kubevirt-utils/components/toggles/DropdownToggle';
 4	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
 5	import { useClickOutside } from '@kubevirt-utils/hooks/useClickOutside/useClickOutside';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { Menu, MenuContent, MenuList, Popper, Tooltip } from '@patternfly/react-core';
 8	
 9	import ActionDropdownItem from '../ActionDropdownItem/ActionDropdownItem';
10	
11	import { ActionDropdownItemType } from './constants';
12	
13	type ActionsDropdownProps = {
14	  actions: ActionDropdownItemType[];
15	  className?: string;
16	  disabledTooltip?: ReactNode;
17	  id?: string;
18	  isDisabled?: boolean;
19	  isKebabToggle?: boolean;
20	  onLazyClick?: () => void;
21	  variant?: 'default' | 'plain' | 'plainText' | 'primary' | 'secondary' | 'typeahead';
22	};
23	
24	const ActionsDropdown: FC<ActionsDropdownProps> = ({
25	  actions = [],
26	  disabledTooltip,
27	  isDisabled,
28	  isKebabToggle,
29	  onLazyClick,
30	  variant,
31	}) => {
32	  const { t } = useKubevirtTranslation();
33	  const [isOpen, setIsOpen] = useState(false);
34	  const menuRef = useRef<HTMLDivElement>(null);
35	  const toggleRef = useRef<HTMLButtonElement>(null);
36	  const containerRef = useRef<HTMLDivElement>(null);
37	
38	  useClickOutside([menuRef, toggleRef], () => setIsOpen(false));
39	
40	  const onToggle = () => {
41	    setIsOpen((prevIsOpen) => {
42	      if (onLazyClick && !prevIsOpen) onLazyClick();
43	
44	      return !prevIsOpen;
45	    });
46	  };
47	
48	  const Toggle = isKebabToggle
49	    ? KebabToggle({ isDisabled, isExpanded: isOpen, onClick: onToggle })
50	    : DropdownToggle({
51	        children: t('Actions'),
52	        isDisabled,
53	        isExpanded: isOpen,
54	        onClick: onToggle,
55	        variant,
56	      });
57	
58	  if (isDisabled)
59	    return (
60	      <div className="kv-actions-dropdown" ref={containerRef}>
61	        <Tooltip content={disabledTooltip}>
62	          <span> {Toggle(toggleRef)}</span>
63	        </Tooltip>
64	      </div>
65	    );
66	
67	  return (
68	    <div className="kv-actions-dropdown" ref={containerRef}>
69	      {Toggle(toggleRef)}
70	      <Popper
71	        popper={
72	          <Menu containsFlyout ref={menuRef}>
73	            <MenuContent>
74	              <MenuList>
75	                {actions?.map((action) => (
76	                  <ActionDropdownItem action={action} key={action?.id} setIsOpen={setIsOpen} />
77	                ))}
78	              </MenuList>
79	            </MenuContent>
80	          </Menu>
81	        }
82	        appendTo={containerRef.current}
83	        isVisible={isOpen}
84	        placement="bottom-end"
85	        triggerRef={toggleRef}
86	      />
87	    </div>
88	  );
89	};
90	
91	export default memo(ActionsDropdown);

